css:
/* ── Xentral Original: klassisch DIN, schwarz auf weiß, keine Farbflächen ── */
.doc-header__brand { max-width: 100%; flex: 1 1 auto; min-width: 0; }
.doc-header__sender { display: none; }
.box-subject h1 { font-size: 13pt; }

.head-cols { display: flex; justify-content: space-between; align-items: flex-start; gap: 10mm; margin: 8mm 0 6mm; }
.head-cols__addr { flex: 1 1 auto; min-width: 0; }
.head-cols__addr .box-recipient { margin: 0; }
.head-cols__info { flex: 0 0 64mm; }
.head-cols__info .box-info { margin: 0; }
.head-cols__info .box-info table { width: 100%; border-collapse: collapse; }
.head-cols__info .box-info th { white-space: nowrap; padding: 0.6mm 4mm 0.6mm 0; }
.head-cols__info .box-info td { text-align: right; }

@page {
  @top-right { content: none; }
  @bottom-center {
    content: "Seite " counter(page) " von " counter(pages);
    font-size: 6.5pt; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; vertical-align: top; padding-top: 4mm;
  }
}

/* Swiss QR-Bill — 105mm hohe Section am Seitenfuß, zweispaltig:
   Empfangsschein 62mm | Zahlteil 148mm (Swiss Payment Standard 2022).
   Schnittlinien zwischen den Spalten + zum oberen Beleg-Bereich.
   Schriftgröße absichtlich klein (Standard: 8-10pt) damit alles
   ins enge Postformular passt. */

.qr-bill {
  margin-top: 24mm;
  page-break-inside: avoid;
  border-top: 0.5mm dashed #6b7280;
  display: grid;
  grid-template-columns: 62mm 148mm;
  min-height: 105mm;
  font-size: 9pt;
  line-height: 1.3;
  color: #111827;
}

.qr-bill__sr {
  position: absolute;
  width: 1px; height: 1px;
  overflow: hidden;
  clip: rect(0 0 0 0);
}

.qr-bill__receipt {
  padding: 5mm;
  border-right: 0.5mm dashed #6b7280;
  display: flex;
  flex-direction: column;
}

.qr-bill__payment {
  padding: 5mm;
  display: grid;
  grid-template-columns: 51mm 1fr;
  gap: 5mm;
  grid-template-areas:
    "title  title"
    "qr     details"
    "amount details";
  grid-template-rows: auto 51mm 1fr;
}

.qr-bill__small-title,
.qr-bill__title {
  font-weight: 700;
  font-size: 11pt;
  margin-bottom: 3mm;
}
.qr-bill__title { grid-area: title; }

.qr-bill__small-label {
  font-weight: 700;
  font-size: 7pt;
  text-transform: uppercase;
  letter-spacing: 0.2px;
  color: #4b5563;
  margin-top: 2mm;
}

.qr-bill__small-value {
  margin-bottom: 1.5mm;
}

.qr-bill__currency-amount {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 3mm;
  margin-top: auto;
  padding-top: 2mm;
}

.qr-bill__accept {
  font-weight: 700;
  font-size: 7pt;
  text-transform: uppercase;
  text-align: right;
  margin-top: 3mm;
  color: #4b5563;
}

/* QR-Code-Platzhalter — exakt 46×46mm laut Standard. Hier nur ein
   Quadrat mit Hinweis-Buchstaben; bei Echtbetrieb wird das durch das
   <img src="data:image/png;base64,..."> mit dem real generierten
   QR-Bild ersetzt. */
.qr-bill__qr-placeholder {
  grid-area: qr;
  width: 46mm;
  height: 46mm;
  background:
    repeating-linear-gradient(45deg,
      rgba(15,23,42,0.06) 0 2mm,
      rgba(15,23,42,0.03) 2mm 4mm);
  border: 0.3mm solid #111827;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}
.qr-bill__qr-inner {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 2mm;
  color: #4b5563;
}
.qr-bill__qr-text {
  font-weight: 700;
  font-size: 14pt;
  letter-spacing: 1pt;
}
.qr-bill__qr-cross {
  /* Schweizer-Kreuz-Andeutung — Centro-Symbol. Echtes Logo ist
     14×14mm und mittig im QR-Code, hier nur als Hinweis. */
  width: 8mm;
  height: 8mm;
  background: #dc2626;
  color: #fff;
  font-weight: 900;
  font-size: 10pt;
  line-height: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 1mm;
}

.qr-bill__amount-block {
  grid-area: amount;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 3mm;
  align-self: end;
}
.qr-bill__amount-value {
  font-size: 12pt;
  font-weight: 600;
}

.qr-bill__details {
  grid-area: details;
  border-left: 0.3mm solid #d1d5db;
  padding-left: 5mm;
  font-size: 9pt;
}
